//! Spec-compliance edge cases: Spacing & Indentation Interactions
//!
//! These tests target behavioral edge cases in OOXML paragraph spacing and
//! indentation where precedence rules and value interpretation differ from
//! naive implementation.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::LineSpacingRule;

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/edge-cases";

// ── EC-07: contextualSpacing ─────────────────────────────────────────────

/// ISO 29500-1 §17.3.1.9: contextualSpacing suppresses before/after spacing
/// between adjacent paragraphs that share the same paragraph style.
///
/// The fixture has:
///   P1: StyleA (contextualSpacing on style, before=240, after=240)
///   P2: StyleA (same style — spacing between P1/P2 should be suppressed)
///   P3: StyleB (different style — spacing between P2/P3 should be kept)
///
/// This test verifies that:
/// 1. Spacing values from the style are resolved on the paragraphs
/// 2. Style IDs are preserved so a consumer could apply contextualSpacing logic
/// 3. contextual_spacing is resolved from the style definition
#[test]
fn ec07_contextual_spacing_style_ids_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "contextual-spacing");

    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 3,
        "should have at least 3 paragraphs, got {}",
        paras.len()
    );

    // P1 and P2 should both have StyleA
    let p1 = &paras[0];
    let p2 = &paras[1];
    let p3 = &paras[2];

    assert_eq!(
        p1.style_id.as_deref(),
        Some("StyleA"),
        "P1 should have style_id='StyleA'"
    );
    assert_eq!(
        p2.style_id.as_deref(),
        Some("StyleA"),
        "P2 should have style_id='StyleA'"
    );
    assert_eq!(
        p3.style_id.as_deref(),
        Some("StyleB"),
        "P3 should have style_id='StyleB'"
    );

    // Both P1 and P2 should have resolved spacing from StyleA (before=240, after=240)
    let sp1 = p1
        .spacing
        .as_ref()
        .expect("P1 should have spacing from StyleA");
    assert_eq!(
        sp1.before,
        Some(240),
        "P1 spacing.before should be 240 (from StyleA)"
    );
    assert_eq!(
        sp1.after,
        Some(240),
        "P1 spacing.after should be 240 (from StyleA)"
    );

    let sp2 = p2
        .spacing
        .as_ref()
        .expect("P2 should have spacing from StyleA");
    assert_eq!(
        sp2.before,
        Some(240),
        "P2 spacing.before should be 240 (from StyleA)"
    );

    // P3 should have spacing from StyleB (before=480, after=480)
    let sp3 = p3
        .spacing
        .as_ref()
        .expect("P3 should have spacing from StyleB");
    assert_eq!(
        sp3.before,
        Some(480),
        "P3 spacing.before should be 480 (from StyleB)"
    );
    assert_eq!(
        sp3.after,
        Some(480),
        "P3 spacing.after should be 480 (from StyleB)"
    );

    // contextualSpacing is set on StyleA's pPr — should resolve to Some(true) for P1 and P2
    assert_eq!(
        p1.contextual_spacing,
        Some(true),
        "P1 should have contextual_spacing=Some(true) (from StyleA)"
    );
    assert_eq!(
        p2.contextual_spacing,
        Some(true),
        "P2 should have contextual_spacing=Some(true) (from StyleA)"
    );
    // StyleB does not have contextualSpacing — P3 should be None
    assert_eq!(
        p3.contextual_spacing, None,
        "P3 should have contextual_spacing=None (StyleB has no contextualSpacing)"
    );
}

// ── EC-08: spacing line + lineRule ───────────────────────────────────────

/// ISO 29500-1 §17.3.1.33: The lineRule attribute controls how the line value
/// is interpreted:
///   - "auto": value in 240ths of a line (240=single, 360=1.5, 480=double)
///   - "exact": value in twips (exact height)
///   - "atLeast": value in twips (minimum height)
///
/// The fixture has 5 paragraphs with different line/lineRule combinations.
/// Both the numeric value AND the rule must be preserved correctly.
#[test]
fn ec08_spacing_line_auto_single() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-line-rules");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 5,
        "should have at least 5 paragraphs, got {}",
        paras.len()
    );

    // P1: line=240, lineRule=auto (single spacing)
    let sp1 = paras[0].spacing.as_ref().expect("P1 should have spacing");
    assert_eq!(sp1.line, Some(240), "P1 line should be 240");
    assert_eq!(
        sp1.line_rule,
        Some(LineSpacingRule::Auto),
        "P1 lineRule should be Auto"
    );
}

#[test]
fn ec08_spacing_line_auto_one_point_five() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-line-rules");
    let paras = common::all_paragraphs(&doc);

    // P2: line=360, lineRule=auto (1.5 spacing)
    let sp2 = paras[1].spacing.as_ref().expect("P2 should have spacing");
    assert_eq!(sp2.line, Some(360), "P2 line should be 360");
    assert_eq!(
        sp2.line_rule,
        Some(LineSpacingRule::Auto),
        "P2 lineRule should be Auto"
    );
}

