// ── EC-09: spacing before/after "0" vs absent ────────────────────────────

/// ISO 29500-1 §17.3.1.33: Explicit before="0" overrides style's before value.
/// Absent w:before means inherit from style.
///
/// Fixture:
///   SpacedStyle defines before=240, after=240.
///   P1: SpacedStyle, no direct override -> inherits before=240, after=240
///   P2: SpacedStyle, direct before="0" -> before=0, after=240
///   P3: SpacedStyle, direct after="0"  -> before=240, after=0
///   P4: SpacedStyle, direct before="0" AND after="0" -> both 0
#[test]
fn ec09_spacing_inherits_from_style_when_absent() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-zero-vs-absent");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 4,
        "should have at least 4 paragraphs, got {}",
        paras.len()
    );

    // P1: no direct override — should inherit before=240, after=240 from SpacedStyle
    let sp1 = paras[0]
        .spacing
        .as_ref()
        .expect("P1 should have spacing inherited from SpacedStyle (before=240, after=240)");
    assert_eq!(
        sp1.before,
        Some(240),
        "P1 spacing.before should be 240 (inherited from style)"
    );
    assert_eq!(
        sp1.after,
        Some(240),
        "P1 spacing.after should be 240 (inherited from style)"
    );
}

#[test]
fn ec09_spacing_explicit_zero_before_overrides_style() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-zero-vs-absent");
    let paras = common::all_paragraphs(&doc);

    // P2: direct before="0" — should override style's before=240
    let sp2 = paras[1].spacing.as_ref().expect("P2 should have spacing");
    assert_eq!(
        sp2.before,
        Some(0),
        "P2 spacing.before should be 0 (direct override of style's 240). \
         Explicit before='0' is NOT the same as absent — it means zero spacing."
    );
    // Per-attribute inheritance (§17.3.1.33): absent after inherits from style.
    assert_eq!(
        sp2.after,
        Some(240),
        "P2 spacing.after should inherit 240 from style (per-attribute, §17.3.1.33)"
    );
}

#[test]
fn ec09_spacing_explicit_zero_after_overrides_style() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-zero-vs-absent");
    let paras = common::all_paragraphs(&doc);

    // P3: direct after="0" — per-attribute override, before inherits from style.
    let sp3 = paras[2].spacing.as_ref().expect("P3 should have spacing");
    assert_eq!(
        sp3.before,
        Some(240),
        "P3 spacing.before should inherit 240 from style (per-attribute, §17.3.1.33)"
    );
    assert_eq!(
        sp3.after,
        Some(0),
        "P3 spacing.after should be 0 (direct override of style's 240)"
    );
}

#[test]
fn ec09_spacing_explicit_zero_both_overrides_style() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-zero-vs-absent");
    let paras = common::all_paragraphs(&doc);

    // P4: direct before="0" AND after="0" — both override style
    let sp4 = paras[3].spacing.as_ref().expect("P4 should have spacing");
    assert_eq!(
        sp4.before,
        Some(0),
        "P4 spacing.before should be 0 (direct override)"
    );
    assert_eq!(
        sp4.after,
        Some(0),
        "P4 spacing.after should be 0 (direct override)"
    );
}

// ── EC-12: beforeLines/afterLines precedence ─────────────────────────────

/// ISO 29500-1 §17.3.1.33: When beforeLines is specified alongside before,
/// beforeLines takes precedence. beforeLines is in hundredths of a line.
///
/// Fixture:
///   P1: before=480, beforeLines=100 (both present)
///   P2: before=480 only
///   P3: after=480, afterLines=100 (both present)
///   P4: beforeLines=200 only (no before)
#[test]
fn ec12_before_lines_is_present_in_fixture() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-before-after-lines");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 4,
        "should have at least 4 paragraphs, got {}",
        paras.len()
    );

    // P2: before=480 only (no beforeLines) — straightforward
    let sp2 = paras[1].spacing.as_ref().expect("P2 should have spacing");
    assert_eq!(
        sp2.before,
        Some(480),
        "P2 spacing.before should be 480 (no beforeLines conflict)"
    );
    assert_eq!(
        sp2.before_lines, None,
        "P2 spacing.before_lines should be None"
    );
}

/// ISO 29500-1 §17.3.1.33: When beforeLines is specified alongside before,
/// beforeLines takes precedence. Both values are exposed in the model;
/// consumers should prefer before_lines over before when present.
#[test]
fn ec12_before_lines_precedence_over_before() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-before-after-lines");
    let paras = common::all_paragraphs(&doc);

    // P1: before=480, beforeLines=100 — both exposed, consumer picks beforeLines
    let sp1 = paras[0].spacing.as_ref().expect("P1 should have spacing");
    assert_eq!(sp1.before, Some(480), "P1 spacing.before should be 480");
    assert_eq!(
        sp1.before_lines,
        Some(100),
        "P1 spacing.before_lines should be 100"
    );
}

/// ISO 29500-1 §17.3.1.33: afterLines takes precedence over after when both present.
#[test]
fn ec12_after_lines_precedence_over_after() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-before-after-lines");
    let paras = common::all_paragraphs(&doc);

    // P3: after=480, afterLines=100 — both exposed, consumer picks afterLines
    let sp3 = paras[2].spacing.as_ref().expect("P3 should have spacing");
    assert_eq!(sp3.after, Some(480), "P3 spacing.after should be 480");
    assert_eq!(
        sp3.after_lines,
        Some(100),
        "P3 spacing.after_lines should be 100"
    );
}

/// ISO 29500-1 §17.3.1.33: beforeLines=200 with no before — only before_lines exposed.
#[test]
fn ec12_before_lines_only() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "spacing-before-after-lines");
    let paras = common::all_paragraphs(&doc);

    // P4: beforeLines=200 only (no before)
    let sp4 = paras[3].spacing.as_ref().expect("P4 should have spacing");
    assert_eq!(sp4.before, None, "P4 spacing.before should be None");
    assert_eq!(
        sp4.before_lines,
        Some(200),
        "P4 spacing.before_lines should be 200"
    );
}

// ── EC-13: negative left indent ──────────────────────────────────────────

/// ISO 29500-1 §17.3.1.12: left indent can be negative (outdent).
/// The domain model uses `Option<i32>` for left indent, which supports
/// negative values. This test verifies they are preserved correctly.
#[test]
fn ec13_negative_left_indent_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "indent-negative-left");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 4,
        "should have at least 4 paragraphs, got {}",
        paras.len()
    );

    // P1: left=-720 (negative outdent)
    let ind1 = paras[0]
        .indent
        .as_ref()
        .expect("P1 should have indent with left=-720");
    assert_eq!(
        ind1.left,
        Some(-720),
        "P1 indent.left should be -720 (negative outdent). \
         Negative indents are valid per spec — they must be preserved as signed values."
    );
}

/// ISO 29500-1 §17.3.1.12: Explicit left="0" overrides style's left indent.
#[test]
fn ec13_explicit_zero_indent_overrides_style() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "indent-negative-left");
    let paras = common::all_paragraphs(&doc);

    // P2: IndentedStyle (left=720) with direct left="0" override
    let ind2 = paras[1]
        .indent
        .as_ref()
        .expect("P2 should have indent (explicit zero override)");
    assert_eq!(
        ind2.left,
        Some(0),
        "P2 indent.left should be 0 (direct override of style's 720). \
         Explicit left='0' is NOT the same as absent — it means zero indent."
    );
}

/// ISO 29500-1 §17.3.1.12: Absent left indent inherits from style.
#[test]
fn ec13_absent_indent_inherits_from_style() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "indent-negative-left");
    let paras = common::all_paragraphs(&doc);

    // P3: IndentedStyle (left=720), no direct indent -> inherits left=720
    let ind3 = paras[2]
        .indent
        .as_ref()
        .expect("P3 should have indent inherited from IndentedStyle (left=720)");
    assert_eq!(
        ind3.left,
        Some(720),
        "P3 indent.left should be 720 (inherited from IndentedStyle)"
    );
}

/// ISO 29500-1 §17.3.1.12: Negative left with positive firstLine is valid.
#[test]
fn ec13_negative_left_with_first_line() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "indent-negative-left");
    let paras = common::all_paragraphs(&doc);

    // P4: left=-360, firstLine=720
    let ind4 = paras[3]
        .indent
        .as_ref()
        .expect("P4 should have indent (negative left + firstLine)");
    assert_eq!(
        ind4.left,
        Some(-360),
        "P4 indent.left should be -360 (negative outdent)"
    );
    assert_eq!(
        ind4.effective_first_line_twips,
        Some(720),
        "P4 indent.effective_first_line_twips should be 720 (positive first-line indent)"
    );
}
